INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24001, 24, 10046, 2, "2030/12/17 14:59:59", 102301, 0.0, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 401, "2020/07/31 12:00:00", "アヤネ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24002, 24, 10046, 1, "2030/12/17 14:59:59", 102301, 0.0, 0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 402, "2020/07/31 12:00:00", "アヤネ", 2, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24003, 24, 10046, 2, "2030/12/17 14:59:59", 102301, 0.0, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 403, "2020/07/31 12:00:00", "アヤネ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24004, 24, 10046, 2, "2030/12/17 14:59:59", 192201, 0.0, 0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 701, "2020/07/31 12:00:00", "アサヒ", 1, 1.99);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24005, 24, 10046, 1, "2030/12/17 14:59:59", 192201, 0.0, 0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 702, "2020/07/31 12:00:00", "アサヒ", 2, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24006, 24, 10046, 2, "2030/12/17 14:59:59", 192201, 0.0, 0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 703, "2020/07/31 12:00:00", "アサヒ", 1, 3.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24007, 24, 10046, 2, "2030/12/17 14:59:59", 192301, 0.0, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 801, "2020/07/31 12:00:00", "部員３", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24008, 24, 10046, 1, "2030/12/17 14:59:59", 192301, 0.0, 0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 802, "2020/07/31 12:00:00", "部員３", 2, 2.68);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24009, 24, 10046, 2, "2030/12/17 14:59:59", 192301, 0.0, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 803, "2020/07/31 12:00:00", "部員３", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24010, 24, 10046, 1, "2030/12/17 14:59:59", 192501, 0.0, 0.0, "やった！", 501, "2020/07/31 12:00:00", "", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24011, 24, 10046, 1, "2030/12/17 14:59:59", 192501, 0.0, 0.0, "勝ったよ！", 502, "2020/07/31 12:00:00", "", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24012, 24, 10046, 1, "2030/12/17 14:59:59", 192501, 0.0, 0.0, "いい調子！", 503, "2020/07/31 12:00:00", "", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24013, 24, 10046, 6, "2030/12/17 14:59:59", 113501, 0.0, 0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 111, "2020/07/31 12:00:00", "ミサト", 2, 5.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24014, 24, 10046, 1, "2030/12/17 14:59:59", 113501, 0.0, 0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 112, "2020/07/31 12:00:00", "ミサト", 2, 6.85);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24015, 24, 10046, 1, "2030/12/17 14:59:59", 113501, 0.0, 0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113, "2020/07/31 12:00:00", "ミサト", 2, 3.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24016, 24, 10046, 1, "2030/12/17 14:59:59", 192401, 0.0, 0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 611, "2020/07/31 12:00:00", "ダイチ", 2, 6.11);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24017, 24, 10046, 1, "2030/12/17 14:59:59", 192401, 0.0, 0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 612, "2020/07/31 12:00:00", "ダイチ", 2, 6.75);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24018, 24, 10046, 2, "2030/12/17 14:59:59", 192401, 0.0, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 613, "2020/07/31 12:00:00", "ダイチ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24019, 24, 10046, 2, "2030/12/17 14:59:59", 113401, 0.0, 0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 211, "2020/07/31 12:00:00", "ハツネ", 1, 4.52);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24020, 24, 10046, 2, "2030/12/17 14:59:59", 113401, 0.0, 0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 212, "2020/07/31 12:00:00", "ハツネ", 1, 3.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24021, 24, 10046, 1, "2030/12/17 14:59:59", 113401, 0.0, 0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 213, "2020/07/31 12:00:00", "ハツネ", 2, 13.49);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24022, 24, 10046, 1, "2030/12/17 14:59:59", 106501, 0.0, 0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 311, "2020/07/31 12:00:00", "カヤ", 2, 3.17);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24023, 24, 10046, 1, "2030/12/17 14:59:59", 106501, 0.0, 0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 312, "2020/07/31 12:00:00", "カヤ", 2, 4.42);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24024, 24, 10046, 6, "2030/12/17 14:59:59", 106501, 0.0, 0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 313, "2020/07/31 12:00:00", "カヤ", 1, 2.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24025, 24, 10046, 4, "2030/12/17 14:59:59", 102301, 0.0, 0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 421, "2020/07/31 12:00:00", "アヤネ", 3, 3.71);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24026, 24, 10046, 2, "2030/12/17 14:59:59", 192201, 0.0, 0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 721, "2020/07/31 12:00:00", "アサヒ", 1, 5.1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24027, 24, 10046, 1, "2030/12/17 14:59:59", 192301, 0.0, 0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 821, "2020/07/31 12:00:00", "部員３", 3, 4.34);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24028, 24, 10046, 1, "2030/12/17 14:59:59", 192501, 0.0, 0.0, "いい勝負だったよ\nまたやろうね", 521, "2020/07/31 12:00:00", "", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24029, 24, 10046, 1, "2030/12/17 14:59:59", 113501, 0.0, -360.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 101, "2020/07/31 12:00:00", "ミサト", 2, 5.62);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24030, 24, 10046, 1, "2030/12/17 14:59:59", 113501, 0.0, -360.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 102, "2020/07/31 12:00:00", "ミサト", 2, 9.58);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24031, 24, 10046, 2, "2030/12/17 14:59:59", 113501, 0.0, -360.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 103, "2020/07/31 12:00:00", "ミサト", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24032, 24, 10046, 2, "2030/12/17 14:59:59", 113501, 0.0, -360.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 104, "2020/07/31 12:00:00", "ミサト", 1, 9.13);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24033, 24, 10046, 1, "2030/12/17 14:59:59", 113501, 0.0, -360.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 105, "2020/07/31 12:00:00", "ミサト", 2, 8.27);
